   316|export async function updateRequestStatus(
   317|  requestId: string,
   318|  status: EquipmentRequest['status'],
   319|  currentUid: string
   320|): Promise<void> {
   321|  const db = getFirebaseDb();
   322|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   323|
   324|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   325|  if (!snap.exists()) throw new Error('Request not found');
   326|
   327|  const request = snap.data();
   328|  const isProvider = request.providerUid === currentUid;
   329|  const isCustomer = request.customerUid === currentUid;
   330|
   331|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   332|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   333|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   334|    in_progress: { allowed: ['completed'], who: 'provider' },
   335|  };
   336|
   337|  const current = request.status as string;
   338|  const rule = validTransitions[current];
   339|
   340|  if (!rule || !rule.allowed.includes(status)) {
   341|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   342|  }
   343|
   344|  if (rule.who === 'provider' && !isProvider) {
   345|    throw new Error('Only the provider can perform this action');
   346|  }
   347|
   348|  if (status === 'cancelled' && !isCustomer && !isProvider) {
   349|    throw new Error('Only participants can cancel');
   350|  }
   351|
   352|  const updates: Record<string, unknown> = {
   353|    status,
   354|    updatedAt: serverTimestamp(),
   355|  };
   356|
   357|  if (status === 'accepted') {
   358|    updates.allowChat = true;
   359|  }
   360|
   361|  if (status === 'completed' || status === 'rejected' || status === 'cancelled') {
   362|    updates.allowChat = false;
   363|  }
   364|
   365|  await updateDoc(doc(db, 'equipmentRequests', requestId), updates);
   366|  console.log('[Firestore] Request status updated');
   367|}
